/**
 * Generate Suno firewall config.
 *
 * Data source: https://sunoapi.org/docs
 *
 * SunoAPI authenticates with a Bearer token on
 * `https://api.sunoapi.org/...`.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://sunoapi.org/docs";
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Suno API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:suno",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const sunoFirewall = {",
    '  name: "suno",',
    '  description: "Suno API",',
    "  placeholders: {",
    `    SUNO_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.sunoapi.org",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.SUNO_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Suno firewall config...");
  const ts = generateTypeScript();
  writeOutput("suno", ts, import.meta.dirname);
}
